# Basic descriptor
class Validated:
    """Descriptor that validates values."""

    def __init__(self, name, validator):
        self.name = name
        self.validator = validator

    def __set_name__(self, owner, name):
        """Called when the descriptor is assigned to a class attribute."""
        self.name = name

    def __get__(self, obj, objtype=None):
        if obj is None:
            return self  # Access from class returns descriptor itself
        return obj.__dict__.get(self.name)

    def __set__(self, obj, value):
        if not self.validator(value):
            raise ValueError(f"Invalid value for {self.name}: {value}")
        obj.__dict__[self.name] = value

    def __delete__(self, obj):
        del obj.__dict__[self.name]

# Usage
class User:
    name = Validated('name', lambda v: isinstance(v, str) and len(v) > 0)
    age = Validated('age', lambda v: isinstance(v, int) and 0 < v < 150)
    email = Validated('email', lambda v: isinstance(v, str) and '@' in v)

user = User()
user.name = 'Alice'      # Calls Validated.__set__
user.age = 30            # Validated
user.email = 'a@b.com'   # Validated

print(user.name)  # Calls Validated.__get__ -> 'Alice'

