# How property() is a descriptor under the hood
class Property:
    """Simplified reimplementation of built-in property."""

    def __init__(self, fget=None, fset=None, fdel=None):
        self.fget = fget
        self.fset = fset
        self.fdel = fdel

    def __get__(self, obj, objtype=None):
        if obj is None:
            return self
        if self.fget is None:
            raise AttributeError('unreadable attribute')
        return self.fget(obj)

    def __set__(self, obj, value):
        if self.fset is None:
            raise AttributeError("can't set attribute")
        self.fset(obj, value)

    def setter(self, fset):
        return type(self)(self.fget, fset, self.fdel)

class TypedField:
    def __init__(self, expected_type):
        self.type = expected_type
    def __set_name__(self, owner, name):
        self.name = name
    def __get__(self, obj, cls):
        return obj.__dict__.get(self.name) if obj else self
    def __set__(self, obj, value):
        if not isinstance(value, self.type):
            raise TypeError(f"{self.name} must be {self.type.__name__}")
        obj.__dict__[self.name] = value

class User:
    name = TypedField(str)
    age = TypedField(int)

