# Custom metaclass
class RegistryMeta(type):
    """Metaclass that auto-registers all classes."""
    _registry = {}

    def __new__(mcs, name, bases, namespace):
        cls = super().__new__(mcs, name, bases, namespace)
        if bases:  # Don't register the base class itself
            RegistryMeta._registry[name] = cls
        return cls

    @classmethod
    def get_registry(mcs):
        return dict(mcs._registry)

class Plugin(metaclass=RegistryMeta):
    pass

class AudioPlugin(Plugin):
    def process(self):
        return "Processing audio"

class VideoPlugin(Plugin):
    def process(self):
        return "Processing video"

# Plugins are auto-registered
print(RegistryMeta.get_registry())
# {'AudioPlugin': <class 'AudioPlugin'>, 'VideoPlugin': <class 'VideoPlugin'>}

# Metaclass for validation
class ValidatedMeta(type):
    def __new__(mcs, name, bases, namespace):
        # Ensure all subclasses implement required methods
        if bases:  # Skip the base class
            required = getattr(bases[0], '_required_methods', [])
            for method in required:
                if method not in namespace:
                    raise TypeError(
                        f"{name} must implement {method}()"
                    )
        return super().__new__(mcs, name, bases, namespace)

class BaseHandler(metaclass=ValidatedMeta):
    _required_methods = ['handle', 'validate']

