# 1. Built-ins vs loops
# Slow
def sum_loop(n):
    total = 0
    for i in range(n):
        total += i
    return total

# Fast (C implementation)
def sum_builtin(n):
    return sum(range(n))

# 2. List comprehension vs loop
# Slow
def squares_loop(n):
    result = []
    for i in range(n):
        result.append(i ** 2)
    return result

# Fast
def squares_comp(n):
    return [i ** 2 for i in range(n)]

# 3. Local variable optimization
def slow_method(self, items):
    for item in items:
        self.process(item)  # Attribute lookup each iteration

def fast_method(self, items):
    process = self.process  # Cache attribute lookup
    for item in items:
        process(item)  # Local lookup (faster)

# 4. String joining
# Slow: O(n^2) due to string immutability
def build_string_bad(n):
    result = ''
    for i in range(n):
        result += str(i) + ','  # Creates new string each time
    return result

# Fast: O(n)
def build_string_good(n):
    return ','.join(str(i) for i in range(n))

# 5. deque vs list for queue operations
def queue_list(n):
    q = []
    for i in range(n):
        q.append(i)
    for _ in range(n):
        q.pop(0)  # O(n) per pop!

def queue_deque(n):
    q = deque()
    for i in range(n):
        q.append(i)
    for _ in range(n):
        q.popleft()  # O(1) per pop!

# 6. lru_cache for memoization
@lru_cache(maxsize=128)
def fibonacci(n):
    if n < 2:
        return n
    return fibonacci(n - 1) + fibonacci(n - 2)

fibonacci(100)  # Instant with caching; O(2^n) without

