# __class_getitem__: generic-like subscript syntax
class TypedList:
    def __init__(self, item_type):
        self._type = item_type
        self._items = []

    def __class_getitem__(cls, item_type):
        """Called when TypedList[int] is used."""
        def factory():
            return cls(item_type)
        factory.__name__ = f"{cls.__name__}[{item_type.__name__}]"
        return factory

    def append(self, item):
        if not isinstance(item, self._type):
            raise TypeError(f"Expected {self._type.__name__}, got {type(item).__name__}")
        self._items.append(item)

    def __repr__(self):
        return f"TypedList[{self._type.__name__}]({self._items})"

