# __set_name__: descriptors know their attribute name
class Field:
    def __set_name__(self, owner, name):
        """Called when Field() is assigned to a class attribute."""
        self.name = name
        self.private_name = f'_{name}'
        print(f"Field '{name}' registered on {owner.__name__}")

    def __get__(self, obj, cls):
        if obj is None:
            return self
        return getattr(obj, self.private_name, None)

    def __set__(self, obj, value):
        setattr(obj, self.private_name, value)

class Model:
    name = Field()   # __set_name__ called: "Field 'name' registered on Model"
    email = Field()  # __set_name__ called: "Field 'email' registered on Model"

